+    }
+
+    /* --- Textarea focus glow --- */
+    #diagram-input:focus {
+      box-shadow: 0 0 20px rgba(76, 201, 255, 0.08);
+    }
+
+    /* --- Keyboard shortcut hint --- */
+    .kbd {
