+      border: 1px solid rgba(255, 255, 255, 0.1);
+      border-radius: 0.25rem;
+      line-height: 1.4;
+    }
+
+    /* --- Footer --- */
+    footer a {
+      color: #4cc9ff;
+      text-decoration: none;
+      transition: color 160ms ease;
+    }
+
+    footer a:hover {
+      color: #7af5c7;
+    }
+
+    /* --- Empty state --- */
+    .gallery-empty {
+      grid-column: 1 / -1;
+      text-align: center;
+      padding: 4rem 2rem;
+    }
