+
+      .stat-grid .text-3xl {
+        font-size: 1.5rem !important;
+      }
+    }
+
+    /* --- Tooltip for keyboard shortcuts --- */
+    .shortcut-hint {
+      opacity: 0;
+      transition: opacity 200ms ease;
+    }
+
+    button:hover .shortcut-hint,
+    button:focus .shortcut-hint {
+      opacity: 1;
+    }
